import { useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';

import constFlaskURL from '../../consts/constFlaskURL'

import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function EditLocality() {
    const [name_locality, setName] = useState('');
    const [latitude, setLatitude] = useState('');
    const [longitude, setLongitude] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();
    const { id } = useParams();

    const handleLogout = async () => {
        setLoading(true);

        try 
        {
            const response = await constFlaskURL.post('/logout');

            if (response.status === 200) 
            {
                setTimeout(() => {
                    navigate('/login');
                }, 1000);
            }
        }
        catch (err) 
        {
            console.error('Logout error:', err);
        } 
        finally 
        {
            setLoading(false);
        }
    };

    const submitLocality = async (e) => {
        e.preventDefault();
        const locality = { name_locality, latitude, longitude };

        try {
            const update_locality = await constFlaskURL.post(`/localities?id=${id}`, locality);

            if (update_locality.status === 200){
                setName('');
                setLatitude('');
                setLongitude('');
                navigate('/localities');
            }
        } catch (error) {
            console.log(error);
        }
    };

    return (
        <div>
            <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                <div className="container-fluid py-2">
                    <Link className="navbar-brand fs-3 fw-bold" to="/main">roads_admin</Link>
                    <div class="btn-group">
                        <button type="button" class="btn btn-info">Пользователь</button>
                        <button type="button" class="btn btn-info dropdown-toggle dropdown-toggle-split" data-bs-toggle="dropdown" aria-expanded="false">
                            <span class="visually-hidden">Переключатель выпадающего списка</span>
                        </button>
                        <ul class="dropdown-menu">
                            <li>
                                <a class="dropdown-item">
                                    <button
                                        onClick={handleLogout} 
                                        className='dropdown-item'
                                        disabled={loading}
                                    >
                                        {loading ? (
                                            <>
                                                <span className='spinner'></span>
                                                Выход...
                                            </>
                                        ) : 'Выйти'}
                                    </button>
                                </a>
                            </li>
                        </ul>
                    </div>
                </div>
            </nav>
            <form className='container' onSubmit={submitLocality}>
                <h1>Редактировнаие населенного пункта</h1>
                <div className='mb-3'>
                    <lable className='form-label'>Населенный пункт</lable>
                    <input 
                        type='text'
                        name='name_road' 
                        value={name_locality.name_locality} 
                        onChange={(e) => setName(e.target.value)}
                        className='form-input'  
                        placeholder='Населенный пункт'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Широта</lable>
                    <input 
                        type='text'
                        name='latitude' 
                        value={latitude.latitude} 
                        onChange={(e) => setLatitude(e.target.value)}
                        className='form-input'  
                        placeholder='Широта'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Долгота</lable>
                    <input 
                        type='text'
                        name='longitude' 
                        value={longitude.longitude} 
                        onChange={(e) => setLongitude(e.target.value)}
                        className='form-input'  
                        placeholder='Долгота'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Сохранить
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/localities')}
                >
                    Назад
                </button>
            </form>
        </div>
    )

};

export default EditLocality;
